3477 /// Helper routine of SimplifyDemandedUseFPClass. It computes Known
3478 /// floating-point classes. It also tries to handle simplifications that can be
3479 /// done based on DemandedMask, but without modifying the Instruction.
3480 Value *InstCombinerImpl::SimplifyMultipleUseDemandedFPClass(
3481     Instruction *I, FPClassTest DemandedMask, KnownFPClass &Known,
3482     const SimplifyQuery &SQ, unsigned Depth) {
