3615 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
3616                                                FPClassTest DemandedMask,
3617                                                KnownFPClass &Known,
3618                                                unsigned Depth) {
3619   Use &U = I->getOperandUse(OpNo);
3620   Value *V = U.get();
3621   Type *VTy = V->getType();
3622 
3623   if (DemandedMask == fcNone) {
3624     if (isa<PoisonValue>(V))
3625       return false;
3626     replaceUse(U, PoisonValue::get(VTy));
3627     return true;
3628   }
3629 
3630   // Handle constant
3631   Instruction *VInst = dyn_cast<Instruction>(V);
3632   if (!VInst) {
3633     // Handle constants and arguments
3634     Known = computeKnownFPClass(V, fcAllFlags, SQ.getWithInstruction(I), Depth);
3635     Known.knownNot(~DemandedMask);
3636 
3637     if (Known.KnownFPClasses == fcNone) {
3638       if (isa<PoisonValue>(V))
3639         return false;
3640       replaceUse(U, PoisonValue::get(VTy));
3641       return true;
3642     }
3643 
3644     // Do not try to replace values which are already constants (unless we are
3645     // folding to poison). Doing so could promote poison elements to non-poison
3646     // constants.
3647     if (isa<Constant>(V))
3648       return false;
3649 
3650     Value *FoldedToConst = getFPClassConstant(VTy, Known.KnownFPClasses);
3651     if (!FoldedToConst || FoldedToConst == V)
3652       return false;
3653 
3654     replaceUse(U, FoldedToConst);
3655     return true;
3656   }
3657 
3658   if (Depth == MaxAnalysisRecursionDepth) {
3659     Known.knownNot(~DemandedMask);
3660     return false;
3661   }
3662 
3663   Value *NewVal;
3664 
3665   if (VInst->hasOneUse()) {
3666     // If the instruction has one use, we can directly simplify it.
3667     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known,
3668                                         SQ.getWithInstruction(I), Depth);
3669   } else {
3670     // If there are multiple uses of this instruction, then we can simplify
3671     // VInst to some other value, but not modify the instruction.
3672     NewVal = SimplifyMultipleUseDemandedFPClass(
3673         VInst, DemandedMask, Known, SQ.getWithInstruction(I), Depth);
3674   }
3675 
3676   if (!NewVal)
3677     return false;
3678   if (Instruction *OpInst = dyn_cast<Instruction>(U))
3679     salvageDebugInfo(*OpInst);
3680 
3681   replaceUse(U, NewVal);
3682   return true;
3683 }
